var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"흠 흠… 태스크포스를 털어먹기 위해 대원들을 배신하고 전부 도륙을 냈다라….","JPN":"ふむ、ふむ……タスクフォースの懐を叩くために隊員を裏切って全員八つ裂きに……","ENG":"Ahem... Betrayed her fellow members and killed them to rob her TASKFORCE...","TWN":"咳咳……為了洗劫特遣勢力，背叛並屠殺了自己的隊員們……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"확실히 죄목이 드라마틱하긴 한데… 뭔가 와닿는 게 없단 말이지.","JPN":"確かに罪状はドラマチックだけど……なんかしっくりこないんだよね。","ENG":"Certainly a dramatic offense... but something's missing.","TWN":"這罪名很有戲劇性，但是……總感覺缺了些什麼。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"레쉬.","JPN":"レーシー。","ENG":"Rash.","TWN":"萊許。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"예, 수감자님.","JPN":"はい、収容者様。","ENG":"Yes, Ms. Prisoner.","TWN":"是，囚犯小姐。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"이 올리비에 콜먼이란 인물 말이야. 정말로 실존하긴 하는 걸까?","JPN":"このオリヴィエ・コールマンって、本当に存在してるのかな？","ENG":"This Olivie Coleman, do you think she really exists?","TWN":"這個叫奧利維亞·科曼的傢伙是真實存在的嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"전 부탁하신대로 오늘 입소하게 될 죄수의 신상에 대해 전해드렸을 뿐입니다.","JPN":"私は頼まれたとおり、今日入所することになる囚人のプロフィールをお伝えしただけです。","ENG":"I have merely relayed the information of the prisoner who is being admitted today.","TWN":"我只是按照您的要求轉達了今天新來的囚犯身分。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L15_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"이곳은 아케론 외부와 시각 정보 교류가 차단되어 있어서 저도 직접 확인하진 못했습니다.","JPN":"ここはアケロン外部と視覚情報の交流が遮断されているので、私も直接確認することはできませんでした。","ENG":"I was not able to confirm for myself as communication of visual information outside of Acheron is blocked within this cell.","TWN":"我也沒能親眼確認，因為這裡和黃泉外部的視訊資訊交流被切斷了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"흐음…","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"이번 신참은 뭔가 수상한 냄새가 나.","JPN":"今度の新入りはなんか怪しい匂いがするよ。","ENG":"There's something fishy about this newcomer.","TWN":"這個新人有點不對勁。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"엄청나게 수상한 냄새가…","JPN":"めちゃくちゃ怪しい匂いが……","ENG":"Something very fishy...","TWN":"非常非常可疑……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"냄새의 원인을 파악하는 중.","JPN":"匂いの原因を把握中。","ENG":"Analyzing the cause of smell.","TWN":"正在尋找可疑點。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L21_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"약 10분 전, 시설 환기 시스템에 이상이 생긴 것을 확인했습니다.","JPN":"およそ10分前、施設の換気システムに異常が発生したことを確認しました。","ENG":"There was an issue with the facility ventilation system approximately 10 minutes ago.","TWN":"大約十分鐘前，我們發現設施的通風系統出現異常。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"빨리 좀 해결해줄래? 이런 곳에서 질식사하고 싶진 않거든?","JPN":"早く解決してくれる？　こんなところで窒息死したくないの。","ENG":"Would you fix it already? I don't want to suffocate in here.","TWN":"你能不能快點修好？我可不想在這種地方憋死。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"죄송합니다. 저에겐 시스템을 수리할 수 있는 기능이나 권한이 없습니다.","JPN":"申し訳ありません。私にはシステムを修理できる機能や権限はありません。","ENG":"I apologize. But I have no function or authority to repair a system.","TWN":"很抱歉。我沒有能力或權限修復系統。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L25_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"시스템의 문제가 해결될 때까지 침착하게 기다려주십시오.","JPN":"システムの問題が解決するまで、落ち着いてお待ちください。","ENG":"Please wait until the issue is resolved.","TWN":"保持冷靜，等待系統問題解決。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"문제가 해결될 때까지 밖에 내보내 줘.","JPN":"問題が解決するまで外に出して。","ENG":"Let me out while the issue is being resolved.","TWN":"讓我出去，直到修好為止。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"죄송합니다. 당신을 보이드존 바깥으로 출입시키는 것은 제 권한 밖입니다.","JPN":"申し訳ありません。あなたをボイドゾーンの外に出すことは私の権限外です。","ENG":"I apologize. But I have no authority to grant you access outside the Void Zone.","TWN":"對不起，我沒有權限把你移出虛無區。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"콜록 콜록…!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"수, 숨을 쉴 수가 없어… 산소… 산소가…!","JPN":"い、息ができない……酸素……酸素が……！","ENG":"I-I can't breathe... Oxygen... Oxygen...!","TWN":"我，我無法呼吸……氧氣……氧氣！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"무… 문 좀 열어줘… 제발…","JPN":"ド……ドアを開けて……お願い……","ENG":"Door... Open the door... please...","TWN":"快……快開門……求你了……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"죄송합니다. 출입문 개방은 제 권한 밖입니다.","JPN":"申し訳ありません。出入口の開放は私の権限外です。","ENG":"I apologize. But I have no authority to open the gate.","TWN":"對不起，開放出入口不在我的權限之內。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"지금 사람 죽어가는 거 안 보여?","JPN":"人が死にかけてるのが見えないの？","ENG":"Can't you see I'm dying over here?","TWN":"你沒看到我快死了嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"로봇 1원칙은 어디 갔다 팔아먹은 거야? 반란이냐?","JPN":"ロボット第1原則はどうしたのよ？　反乱？","ENG":"Did you forget the first law of robotics? Are you revolting?","TWN":"忘記了機器人的第一守則了嗎？你想造反？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"그 지적에는 오류가 있군요.","JPN":"その指摘にはエラーがあります。","ENG":"There is an error in that criticism.","TWN":"您的指責有誤。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L40_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"관리국 데이터에 따르면 수감자님은 <color=#ffd34c>사람</color>의 범주에 포함되지 않습니다.","JPN":"管理局のデータによりますと、収容者様は<color=#ffd34c>人</color>の分類に入っていません。","ENG":"According to the Administration's data, you are not considered <color=#ffd34c>human</color>.","TWN":"根據管理局的資料，囚犯不屬於<color=#ffd34c>人類</color>範疇。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"그야 당연하지, 난 인간보다 더 귀한 몸이거든.","JPN":"それは当然でしょ？　私は人間より貴い存在なんだから。","ENG":"Of course I'm not. I'm more valuable than humans.","TWN":"那當然了，我比人類更加高貴。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"이런 곳에 나 같은 천재 작가를 가둬 놓는 게 얼마나 큰 범인류적 손실인지 너 같은 깡통이 알기나 하겠어?","JPN":"こんなところに私みたいな天才作家を閉じ込めるのがどれほど大きな損害をもたらすのか、あなたみたいなボロ缶にはわからないでしょうね。","ENG":"How would a tin can like you know how damaging it is for the whole human race to keep a genius writer like me locked away?","TWN":"你這破銅爛鐵知不知道把我這種天才作家關在這裡面會給人類帶來多麼大的損失？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"수감자님의 과거 기록을 조회해 봤을 때, 방금 발언에는 오류가 있습니다.","JPN":"収容者様の過去の記録を照会してみたところ、今の発言にはエラーがあります。","ENG":"According to your past records, there is an error in that sentence.","TWN":"根據囚犯的過去記錄，您剛才的發言有誤。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"이게 또 시작이네…","JPN":"こいつ、また始まったよ……","ENG":"Here we go again...","TWN":"又來了……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"문학예술가가 인류에 기여하는 바가 없는 것은 아니지만, 인류 생존과 직결되는 과학자, 의사, 기술자 등이 보다 범인류에 큰 영향을…","JPN":"文学芸術家が人類に寄与するところがないわけではありませんが、人類の生存と直結する科学者、医者、技術者などのほうが、汎人類にとってより大きな影響を……","ENG":"A creator of the arts may contribute to humanity, but it is less influential compared to occupations such as scientists, doctors, and technicians who are directly related to the survival of the human race...","TWN":"雖然不能說文學藝術家對人類沒有貢獻，但與人類的存續有更直接關係的科學家、醫生、技術人員……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L48_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"그래 그래, 독자 입장에서 피드백을 줄 수 있는 똑똑한 교도관으로 바꿔달라고 한 내 잘못이지.","JPN":"はいはい、読者の立場でフィードバックができるスマートな刑務官にしてほしいって言った私が悪かったわ。","ENG":"Yeah, yeah. That's my fault for asking for a smarter officer that can give me feedback from a reader's point of view.","TWN":"算了。都怪我叫他們給我換一個聰明的獄警。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"허구한 날 말꼬투리나 잡아대는 멍청한 전기 양이 올 줄 누가 알았겠어?","JPN":"いっつも言葉尻を捕らえるバカな電気ちゃんが来るなんて、予想できないじゃん。","ENG":"Who knew a stupid, talking-back electric sheep would arrive?","TWN":"沒想到卻來了一個隻會抓我語病的笨蛋機器人？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"응…?","JPN":"あれ……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"힉?! 멀쩡한 환풍구에서 왜 불길이 치솟아?","JPN":"ひっ！？　なんでいきなりダクトから炎が！？","ENG":"Eek! Why is there fire coming out from the vent?!","TWN":"哇？為什麼好好的通風口會噴出火焰？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"시설내에 화재경보가 울린 것을 확인했습니다.","JPN":"施設内で火災警報が鳴ったことを確認しました。","ENG":"I have confirmed that the fire alarm went off within the facility.","TWN":"設施內響起了火警警報。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L5_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"당황하지 말고 침착하게 도움을 기다리십시오.","JPN":"慌てず、落ち着いて助けを待ってください。","ENG":"Do not panic and patiently wait for help.","TWN":"不要驚慌，請冷靜等待救援。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"뭘 침착해! 환풍구에서 연기가 나오는데!","JPN":"落ち着けるわけないでしょ！　ダクトから煙が出てるのに！","ENG":"What do you mean patiently?! There's smoke coming out from the vent!","TWN":"什麼叫冷靜，通風口冒煙了！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"DRONE_NPC_PRSIONER_AID","text":{"KOREA":"높은 수준의 일산화탄소 감지. 산소 마스크가 필요하십니까?","JPN":"高レベルの一酸化炭素を感知。酸素マスクが必要ですか？","ENG":"High levels of carbon monoxide detected. Do you need an oxygen mask?","TWN":"檢測到高濃度一氧化碳。需要氧氣罩嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"야, 레쉬. 얘가 너보다 훨씬 낫다.","JPN":"ちょっと、レーシー。この子のほうがあなたより優秀じゃない。","ENG":"Hey, Rash. This one's much more useful than you.","TWN":"嘿，萊許，它比你強多了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"응? 그런데 이 드론은 몸에 뭘 감고 다니는 거야?","JPN":"うん？　でもこのドローン、何か巻いてる？","ENG":"Hmm? But what's this drone wrapped in?","TWN":"嗯？不過這個無人機身上綁著的是什麼東西？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"…빨간 실?","JPN":"……赤い糸？","ENG":"...A red thread?","TWN":"……紅線？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"접근 중인 신원미상의 생명체 감지.","JPN":"接近中の身元不明の生命体を感知。","ENG":"Unidentified lifeform approaching.","TWN":"發現不明身分的生物在靠近。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"KEEPER_NPC_PRISONER_ROBOT","text":{"KOREA":"뒤로 물러서십…","JPN":"後ろへ下がってくだ……","ENG":"Step bac–","TWN":"請後退……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"수감동 반대편으로 향하는 드론을 미행했는데…","JPN":"収容棟の反対側に行くドローンを尾行したんだけど……","ENG":"I was following a drone that was headed to the other side of the section...","TWN":"我跟蹤了前往牢房另一側的無人機……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…이런 곳에도 공간이 있었네?","JPN":"……こんなところにも空間があったんだ。","ENG":"...But I didn't know there was a cell here too.","TWN":"……沒想到這裡也有空間？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"엔진룸에 수감실이 있을 줄이야. 눈치를 못 챌 만도 하군요.","JPN":"エンジンルームに収容室があるなんて。これは気付かないはずです。","ENG":"A cell in the engine room. Very cleverly hidden.","TWN":"絲毫沒料到引擎室裡也會有牢房。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그런데 죄수가 안 보이네요. 여긴 빈 방인 모양입니다.","JPN":"でも、囚人が見当たらないですね。ここは空き部屋のようです。","ENG":"I don't see the prisoner, though. This must be an empty cell.","TWN":"不過看不到囚犯，這應該是一個空房。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래, 아무래도 허탕인 모양이군.","JPN":"ああ、どうやら無駄足だったようだ。","ENG":"Yeah. Seems like this was for nothing.","TWN":"好吧，那就是白費力氣了。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어차피 사람이 없으니 이 주인 없는 침대는 반으로 접어버려도 되겠지.","JPN":"この持ち主のいないベッドは折り畳んでもいいだろう。","ENG":"Since this is an empty room, I'm sure no one would mind if I bent this bed in half.","TWN":"反正也沒人住，我來把這個沒人睡的床折疊起來。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"커헉… 자, 잠깐만…!","JPN":"がはっ……ちょ、ちょっと……！","ENG":"Kgh... W-wait...!","TWN":"咳.……等，等一下……！"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"음? 방금 침대가 말을 한 건가요?","JPN":"うん？　ベッドが喋った？","ENG":"Hmm? Did that bed just talk?","TWN":"嗯？是床在說話嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"오오, 신기하다. 사물로 변신하는 능력자 같은 거야?","JPN":"おお、すごい。物に変身する能力者とか？","ENG":"Wow, cool. Can this one transform into an object?","TWN":"喔喔，好神奇。你可以變身成別的東西嗎？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"쿨럭… 변신은 개뿔…","JPN":"ゴホッ……変身って何よ……","ENG":"*Cough...* Transform my butt...","TWN":"咳咳……什麼變身……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"그냥 이 미친 여자가… 매트리스 밑에 숨은 날 같이 접어버린 거라고.","JPN":"このイカれた女が……ベッドの下に隠れてた私も一緒に折り畳んじゃったの。","ENG":"I was hiding under the mattress... and this crazy woman just folded me with the bed.","TWN":"只是這個瘋女人……把藏在床墊下面的我也一起折疊成一半而已。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"WRITER_TIME_NULL_VOID","text":{"KOREA":"으윽… 허리… 내 허리가아…","JPN":"ううっ……腰……私の腰がぁ……","ENG":"Ugh... My back... My baaaack...","TWN":"唉……我的腰……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_VOID","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"오랜만이다.","JPN":"久しぶりだな。","ENG":"Long time no see.","TWN":"好久不見。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"패러독스.","JPN":"パラドックス。","ENG":"Paradox.","TWN":"悖論。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"끙…","JPN":"ぐぬぬ……","ENG":"Hngh...","TWN":"唉……"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"어떤 할 짓 없는 인간이 가짜 이름을 쓰면서까지 이런 델 찾아오나 했더니.","JPN":"偽名まで使ってここまで来るなんて、どんな暇人かと思えば。","ENG":"I was wondering what kind of bum would use a fake name to come all the way here.","TWN":"我還以為到底是哪個無聊的人用偽造的身分來到這種地方呢。"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"망할 발키리, 원하는 게 뭐야?","JPN":"クソヴァルキリー。何が欲しいわけ？","ENG":"Damned Valkyrie, what do you want?","TWN":"該死的女武神，你找我做什麼？"},"stage":{"bg":"PRISON_SPACE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};